
UPDATE intake_sessions SET class_group = 'tali' WHERE student_name IN ('אוריאן שיקלי', 'רון מרש', 'הודיה אלחרר', 'יובל אורטס', 'ענהאל שמיאן דהן', 'להב נהוראי', 'ליאן עמאר');
UPDATE intake_sessions SET class_group = 'eden' WHERE student_name IN ('תאיר שקיר', 'אריאל עוז עזרא', 'נעם יחיאב', 'אלה בן דוד', 'איתמר דכינגר', 'אוריאן קדוש', 'ליה קרמר', 'נעם טובי קרלן', 'נחמן דרור', 'אילון שוורץ', 'איתמר דהן', 'עופר יוסף בכר', 'ליה פקנהיים');
